import { useEffect } from "react";

const AppLoader = ({ onFinish }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onFinish();
    }, 1500);

    return () => clearTimeout(timer);
  }, [onFinish]);

  return (
    <>
      <style>
        {`
          .loader-wrapper {
            position: fixed;
            inset: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            gap: 40px;
            z-index: 9999;
            background: var(--theme-bg-primary);
            transition: background 0.3s ease;
          }

          /* Gradient animation for dark theme */
          [data-theme="dark"] .loader-wrapper {
            background: linear-gradient(
              -45deg,
              #080808,
              #0d0d0d,
              #141414,
              #080808
            );
            background-size: 400% 400%;
            animation: gradientMove 8s ease infinite;
          }

          /* Solid background for light theme (softer) */
          [data-theme="light"] .loader-wrapper {
            background: var(--theme-bg-primary);
            animation: none;
          }

          @keyframes gradientMove {
            0% { background-position: 0% 50%; }
            50% { background-position: 100% 50%; }
            100% { background-position: 0% 50%; }
          }

          .loader-text {
            font-size: 48px;
            font-weight: 600;
            letter-spacing: 6px;
            color: var(--theme-text-primary);
            opacity: 0;
            animation: fadeIn 1s ease forwards;
          }

          @keyframes fadeIn {
            to { opacity: 1; }
          }

          .loader {
            --color-one: #ffbf48;
            --color-two: #be4a1d;
            --color-three: #ffbf4780;
            --color-four: #bf4a1d80;
            --color-five: #ffbf4740;
            --time-animation: 2s;
            --size: 1;
            position: relative;
            border-radius: 50%;
            transform: scale(var(--size));
            transition: box-shadow 0.3s ease;
          }

          /* Dark theme loader styles */
          [data-theme="dark"] .loader {
            box-shadow:
              0 0 25px 0 var(--color-three),
              0 20px 50px 0 var(--color-four);
            animation: colorize calc(var(--time-animation) * 3) ease-in-out infinite;
          }

          /* Light theme loader styles - using theme colors */
          [data-theme="light"] .loader {
            box-shadow:
              0 0 25px 0 rgba(122, 63, 145, 0.3),
              0 20px 50px 0 rgba(122, 63, 145, 0.2);
            animation: colorizeLight calc(var(--time-animation) * 3) ease-in-out infinite;
          }

          .loader::before {
            content: "";
            position: absolute;
            top: 0;
            left: 0;
            width: 100px;
            height: 100px;
            border-radius: 50%;
            border-top: solid 1px var(--color-one);
            border-bottom: solid 1px var(--color-two);
            background: linear-gradient(180deg, var(--color-five), var(--color-four));
            box-shadow:
              inset 0 10px 10px 0 var(--color-three),
              inset 0 -10px 10px 0 var(--color-four);
          }

          /* Light theme loader gradient */
          [data-theme="light"] .loader::before {
            border-top: solid 1px var(--theme-primary);
            border-bottom: solid 1px var(--theme-primary-light);
            background: linear-gradient(180deg, rgba(122, 63, 145, 0.2), rgba(197, 157, 217, 0.3));
            box-shadow:
              inset 0 10px 10px 0 rgba(122, 63, 145, 0.2),
              inset 0 -10px 10px 0 rgba(197, 157, 217, 0.2);
          }

          .loader .box {
            width: 100px;
            height: 100px;
            background: linear-gradient(
              180deg,
              var(--color-one) 30%,
              var(--color-two) 70%
            );
            mask: url(#clipping);
            -webkit-mask: url(#clipping);
          }

          /* Light theme box gradient */
          [data-theme="light"] .loader .box {
            background: linear-gradient(
              180deg,
              var(--theme-primary) 30%,
              var(--theme-primary-light) 70%
            );
          }

          .loader svg {
            position: absolute;
          }

          .loader svg #clipping {
            filter: contrast(15);
            animation: roundness calc(var(--time-animation) / 2) linear infinite;
          }

          .loader svg #clipping polygon {
            filter: blur(7px);
          }

          .loader svg #clipping polygon:nth-child(1) {
            transform-origin: 75% 25%;
            transform: rotate(90deg);
          }

          .loader svg #clipping polygon:nth-child(2) {
            transform-origin: 50% 50%;
            animation: rotation var(--time-animation) linear infinite reverse;
          }

          .loader svg #clipping polygon:nth-child(3) {
            transform-origin: 50% 60%;
            animation: rotation var(--time-animation) linear infinite;
            animation-delay: calc(var(--time-animation) / -3);
          }

          .loader svg #clipping polygon:nth-child(4) {
            transform-origin: 40% 40%;
            animation: rotation var(--time-animation) linear infinite reverse;
          }

          .loader svg #clipping polygon:nth-child(5) {
            transform-origin: 40% 40%;
            animation: rotation var(--time-animation) linear infinite reverse;
            animation-delay: calc(var(--time-animation) / -2);
          }

          .loader svg #clipping polygon:nth-child(6) {
            transform-origin: 60% 40%;
            animation: rotation var(--time-animation) linear infinite;
          }

          .loader svg #clipping polygon:nth-child(7) {
            transform-origin: 60% 40%;
            animation: rotation var(--time-animation) linear infinite;
            animation-delay: calc(var(--time-animation) / -1.5);
          }

          @keyframes rotation {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }

          @keyframes roundness {
            0% { filter: contrast(15); }
            20% { filter: contrast(3); }
            40% { filter: contrast(3); }
            60% { filter: contrast(15); }
            100% { filter: contrast(15); }
          }

          @keyframes colorize {
            0% { filter: hue-rotate(0deg); }
            20% { filter: hue-rotate(-30deg); }
            40% { filter: hue-rotate(-60deg); }
            60% { filter: hue-rotate(-90deg); }
            80% { filter: hue-rotate(-45deg); }
            100% { filter: hue-rotate(0deg); }
          }

          /* Light theme color animation - using purple hues */
          @keyframes colorizeLight {
            0% { filter: hue-rotate(0deg); }
            20% { filter: hue-rotate(30deg); }
            40% { filter: hue-rotate(60deg); }
            60% { filter: hue-rotate(90deg); }
            80% { filter: hue-rotate(45deg); }
            100% { filter: hue-rotate(0deg); }
          }
        `}
      </style>

      <div className="loader-wrapper">
        {/* Optional text loader - uncomment if needed */}
        {/* <div className="loader-text">GOPIKA</div> */}

        <div className="loader">
          <svg width="100" height="100" viewBox="0 0 100 100">
            <defs>
              <mask id="clipping">
                <polygon points="0,0 100,0 100,100 0,100" fill="black"></polygon>
                <polygon points="25,25 75,25 50,75" fill="white"></polygon>
                <polygon points="50,25 75,75 25,75" fill="white"></polygon>
                <polygon points="35,35 65,35 50,65" fill="white"></polygon>
                <polygon points="35,35 65,35 50,65" fill="white"></polygon>
                <polygon points="35,35 65,35 50,65" fill="white"></polygon>
                <polygon points="35,35 65,35 50,65" fill="white"></polygon>
              </mask>
            </defs>
          </svg>
          <div className="box"></div>
        </div>
      </div>
    </>
  );
};

export default AppLoader;